import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import org.apache.nifi.processor.io.StreamCallback
import groovy.json.JsonBuilder
import groovy.xml.XmlSlurper

def flowFile = session.get()
if (!flowFile) return

try {
    flowFile = session.write(flowFile, { inputStream, outputStream ->
        String text = IOUtils.toString(inputStream, StandardCharsets.UTF_8)

        text = text.replaceAll(/xmlns(:[a-zA-Z0-9\-]+)?="[^"]*"/, "")
        text = text.replaceAll(/<([a-zA-Z0-9\-]+):/, "<")
        text = text.replaceAll(/<\/([a-zA-Z0-9\-]+):/, "</")

        def root = new XmlSlurper(false, false).parseText(text)

        def counterMap = [:]
        root.'**'.findAll { it.name().contains('measType') }.each { mt ->
            def pVal = mt.@p.text()
            if (pVal && mt.text()) {
                counterMap[pVal] = mt.text().trim()
            }
        }

        def results = []
        root.'**'.findAll { it.name().contains('measValue') }.each { mv ->
            def cellId = mv.@measObjLdn.text() ?: 'unknown_cell'
            def record = [cell_id: cellId]

			// --- ARCHITECTURE FIX 3: Extract Hidden Timestamp ---
			def tsTag = mv.'**'.find { it.name().contains('suspectFlag') }
			if (tsTag) {
    			record['collection_timestamp'] = tsTag.text().trim()
			}        

            def measResultsTag = mv.'**'.find { it.name().contains('measResults') }

            if (measResultsTag) {
                def valuesArray = measResultsTag.text().trim().split("\\s+")

                valuesArray.eachWithIndex { val, idx ->
                    def pVal = (idx + 1).toString()

                    if (counterMap.containsKey(pVal) && val != "None" && val != "null") {
                        def counterName = counterMap[pVal]

                        // --- ARCHITECTURE FIX 1: Rename to match Schema ---
                        if (counterName == "dl_throughput_mbps") {
                            counterName = "throughput_mbps"
                        }

                        try {
                            def numericVal = val.toDouble()

                            // --- ARCHITECTURE FIX 2: CPNI Masking Math ---
                            if (counterName == "active_ue_count") {
                                // Divide by 10, cast to int (truncates decimals), multiply by 10
                                numericVal = (numericVal / 10).intValue() * 10
                            }

                            record[counterName] = numericVal
                        } catch (NumberFormatException e) {
                            record[counterName] = val 
                        }
                    }
                }
            }
            results << record
        }

        def outputData = results.size() == 1 ? results[0] : results
        def jsonString = new JsonBuilder(outputData).toString()
        outputStream.write(jsonString.getBytes(StandardCharsets.UTF_8))

    } as StreamCallback)

    flowFile = session.putAttribute(flowFile, "mime.type", "application/json")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error("Failed to parse PySpark 3GPP XML", e)
    session.transfer(flowFile, REL_FAILURE)
}
